$(document).ready(function(){var params={};function parseQueryString(url){var arr=url.split("?");var arr1=arr[1].split("&");for(var i=0;i<arr1.length;i+=1){arr2=arr1[i].split('=');if(!arr2[1]){params[arr2[0]]='true'}else{if(params[arr2[0]]){var arr3=[params[arr2[0]]];arr3.push(arr2[1]);params[arr2[0]]=arr3}else{params[arr2[0]]=decodeURI(arr2[1])}}}return params}var url=window.location.href;parseQueryString(url);function autoinputval(){$("input[name='sign']").val(params.sign);$("input[name='token']").val(params.token);$("input[name='parent']").val(params.parent)}autoinputval();function obtainqrcode(){var sendData={type:params.type,sign:params.sign};$.ajax({type:'GET',url:'mapi/verify/getqrcode',async:false,data:sendData,dataType:'json',success:function(res){if(res.status==1000){var src="mapi/showloginqrcode/";var token=res.token;$("#token").val(token);var imgsrc=src+token;$('#qrcodeImg1').attr('src',imgsrc);$('#qrcodeImg2').attr('src',imgsrc);$('#qrcodeImg3').attr('src',imgsrc);var loginways=res.authtypes.split(",");$("#loginways"+loginways[0]).show();if(loginways.length>1){$("#moreways").show();for(i=1;i<loginways.length;i+=1){if(i==1){$("#otherwaysButton"+loginways[i]).addClass("active");$("#otherways"+loginways[i]).addClass("active")}$("#otherwaysButton"+loginways[i]).show()}}if(res.wx_qr_uri){$('.weixinUrl').attr('href',res.wx_qr_uri)}}else{layer.msg(res.status,{icon:2})}},error:function(){layer.msg(res.status,{icon:2})}})}obtainqrcode();initParameter();var voiceCallTelNumber="";var defaulteStatusCode='9009';waitAuthResult(defaulteStatusCode,null);var operationRetrytime=3;var bigBtnWaitMsg='';var signExpireTime=280;var ajaxTimeOut=0;var debug=true;reloadPage();$("input[name='username']").change(function(){$("input[name='username']").val($(this).val())});function goQrpage(msg,countdown){messages(msg,{time:countdown,shadeClose:true,shade:[0.8,'#393D49']});setTimeout(function(){$.postMessage('RELOAD_PAGE',decodeURIComponent($('#parent').val()))},countdown)}$(".byPhone").click(function(){var thisBtn=$(this);if(thisBtn.attr('disabled')=='disabled'){return}var username=thisBtn.parent().find("input[name='username']");if(username.attr('placeholder')!="undefined"&&username.val()==''){layer.msg(username.attr('placeholder'),{icon:2});return false}messages('您将收到一个'+voiceCallTelNumber+'的语音电话,请填写收到的验证码');sendAuthRequest(thisBtn,'s',4,username.val(),function(data){phoneTelAuthToken=data.response_body.token})});$(".bysms").click(function(){var thisBtn=$(this);if(thisBtn.attr('disabled')=='disabled'){return}var username=thisBtn.parent().find("input[name='username']");if(username.attr('placeholder')!="undefined"&&!username.val()){layer.msg(username.attr('placeholder'),{icon:2});return false}messages('短信验证码已发送,请在手机查看');sendAuthRequest(thisBtn,'s',3,username.val(),function(data){phoneSMSAuthToken=data.response_body.token})});$(".exeActionBtn").click(function(e){var thisBtn=$(this);if(thisBtn.attr('disabled')=='disabled'){return}authActionEvent(thisBtn);e.preventDefault()});function authActionEvent(thisBtn){var postdata=getPostData(thisBtn);if(!postdata){return}var type=$(thisBtn).parent('[data-index]').attr('data-index');switch(type){case 'akey':akeyAuth(thisBtn,postdata);break;case 'dynpwd':dynPwdAuth(thisBtn,postdata);break;case 'tempauthcode':tempAuthCodeAuth(thisBtn,postdata);break;case 'voiceauth':voiceAuthAuth(thisBtn,postdata);break;case 'smsauth':smsAuth(thisBtn,postdata);break;case 'voiceprintauth':voicePrintAuth(thisBtn,postdata);break;case 'faceauth':faceAuth(thisBtn,postdata);break;case 'pwd':pwdAuth(thisBtn,postdata);break}}function akeyAuth(thisBtn,postdata){messages('正在发起推送,请在手机上确认登录');sendAuthRequest(thisBtn,bigBtnWaitMsg,1,postdata.username,function(data){waitAuthResult(null,data.response_body.token);return})}function voicePrintAuth(thisBtn,postdata){messages('正在发起推送,请在手机上确认登录');sendAuthRequest(thisBtn,bigBtnWaitMsg,7,postdata.username,function(data){waitAuthResult(null,data.response_body.token);return})}function faceAuth(thisBtn,postdata){messages('正在发起推送,请在手机上确认登录');sendAuthRequest(thisBtn,bigBtnWaitMsg,6,postdata.username,function(data){waitAuthResult(null,data.response_body.token);return})}function smsAuth(thisBtn,postdata){if(typeof(phoneSMSAuthToken)=='undefined'){messages('令牌失效,请获取短信验证码');return}checkAuthcode(thisBtn,3,postdata.authcode,(typeof(phoneSMSAuthToken)!='undefined')?phoneSMSAuthToken:'',function(){phoneSMSAuthToken=null},function(data){if(data.status==9001){messages('请重新获取短信验证码');return false}else{showResult(data)}})}function voiceAuthAuth(thisBtn,postdata){if(typeof(phoneTelAuthToken)=='undefined'){messages('令牌失效,请拔打电话获取验证码');return}checkAuthcode(thisBtn,4,postdata.authcode,(typeof(phoneTelAuthToken)!='undefined')?phoneTelAuthToken:'',function(){phoneTelAuthToken=null},function(data){if(data.status==9001){messages('请重新拔打电话获取验证码');return}else{showResult(data)}})}function tempAuthCodeAuth(thisBtn,postdata){sendAuthRequest(thisBtn,bigBtnWaitMsg,5,postdata.username,function(data,btn,countDownMsg){checkAuthcode(thisBtn,5,postdata.authcode,data.response_body.token,null,function(data){if(data.status==9011){messages('您输入的临时授权码错误');return}else{showResult(data)}},btn,countDownMsg);return})}function dynPwdAuth(thisBtn,postdata){sendAuthRequest(thisBtn,bigBtnWaitMsg,2,postdata.username,function(data,btn,countDownMsg){checkAuthcode(thisBtn,2,postdata.authcode,data.response_body.token,null,function(data){if(data.status==9011){messages('您输入的动态令牌错误');return}else{showResult(data)}},btn,countDownMsg)})}function pwdAuth(thisBtn,postdata){sendAuthRequest(thisBtn,bigBtnWaitMsg,11,postdata.username,function(data,btn,countDownMsg){checkAuthcode(thisBtn,11,postdata.authcode,data.response_body.token,null,function(data){if(data.status==9011){messages('用户名或密码错误');return}else{showResult(data)}},btn,countDownMsg)})}function sendAuthRequest(btn,countDownMsg,atype,username,successFun){var countDown=confirmBigBtnWaitingEffect(btn,countDownMsg);console.log(username);var sendData={sign:$('#sign').val(),username:username,type:atype};$.ajax({type:'POST',url:'mapi/verify/othertype',data:sendData,timeout:ajaxTimeOut,dataType:'json',success:function(data){if(data.status=="1000"){if(data.response_body.serialNumber){btn.parent('[data-index]').find("span[data-id='serialNumber']").text('登录序列号：'+data.response_body.serialNumber)}successFun(data,btn,countDown)}else if(data.status==defaulteStatusCode){waitAuthResult(null,data.response_body.token)}else{cancelCountDown(btn,countDown);showResult(data)}}})}function waitAuthResult(status_,token_){token_=token_||$("#token").val();status_=status_||defaulteStatusCode;var ajaxOpt={method:'POST',type:'json',timeout:ajaxTimeOut,url:'mapi/verify/getauthresult',data:{status:status_,sign:$("#sign").val(),token:token_},success:function(data){if(data.status=='1000'){go(data.response_body.usersign)}else{showResult(data)}},error:function(XMLHttpRequest,textStatus,errorThrown){console.log('请求QR Code 出错,code:'+JSON.stringify(XMLHttpRequest))}};$.ajax(ajaxOpt)}function checkAuthcode(thisBtn,atype,code,token,successFun,errorFun,btn,countDown){var username=thisBtn.parent().find("input[name='username']").val();if(!token){console.log('令牌：'+token)}console.log('checkAuthcode token:'+token);console.log('checkAuthcode sign:'+$('#sign').val());var sendData={sign:$('#sign').val(),token:token,authcode:code||'',type:atype,username:username};$.ajax({type:'POST',url:'mapi/verify/checkAuthcode',data:sendData,dataType:'json',timeout:ajaxTimeOut,success:function(data){if(data.status=="1000"){if(successFun){successFun(data)};go(data.response_body.usersign)}else{if(btn&&countDown){cancelCountDown(btn,countDown)}if(errorFun){errorFun(data)}else{showResult(data)}}}})}function go(data){$.postMessage('GO|'+data,decodeURIComponent($('#parent').val()))}function getPostData(thisBtn){var username=$(thisBtn).parent('[data-index]').find("input[name='username']");var authcode=$(thisBtn).parent('[data-index]').find("input[name='authcode']");if(username.attr('placeholder')!="undefined"&&username.val()==''){layer.msg(username.attr('placeholder'),{icon:2});return false}if(authcode&&authcode.attr('placeholder')!="undefined"&&authcode.val()==''){layer.msg(authcode.attr('placeholder'),{icon:2});return false}return{username:username.val(),authcode:authcode.val()}}function confirmBigBtnWaitingEffect(objectBtn,tip){objectBtn.attr('disabled','disabled').css({'cursor':'not-allowed'});if($(objectBtn.attr('id')=='bysms')){objectBtn.addClass('inputbysms')}else if($(objectBtn.attr('id')=='byPhone')){objectBtn.addClass('inputbyPhone')}$('.ssonew-out').addClass('ssonew-out-disable');var inerCd=operationRetrytime;var oriText=objectBtn.text();objectBtn.text('请稍候...');var djs=window.setInterval(function(){inerCd-=1;objectBtn.text('请稍候...');if(inerCd==0){if($(objectBtn.attr('id')=='bysms')){objectBtn.removeClass('inputbysms')}else if($(objectBtn.attr('id')=='byPhone')){objectBtn.removeClass('inputbyPhone')}window.clearInterval(djs);objectBtn.attr('disabled',false).text(oriText).css({'cursor':''});$('.ssonew-out').removeClass('ssonew-out-disable')}},1000);return{index:djs,text:oriText}}function cancelCountDown(btn,obj){window.clearInterval(obj.index);btn.attr('disabled',false).text(obj.text).css({'cursor':''});$('.ssonew-out').removeClass('ssonew-out-disable')}function reloadPage(){if(debug){var count_down=signExpireTime;var cdit=setInterval(function(){count_down-=1;if(count_down<=3){console.log('还剩余'+count_down+'秒过期')}else{console.log(count_down)}if(count_down==0){window.clearInterval(cdit);console.log('签名已过期,跳到认证页面．')}},1000)}setTimeout(function(){goQrpage('会话马上过期,系统将自动跳到初始页面．',2000)},signExpireTime*1000)}function showResult(data,opt){console.log('返回状态:'+data.status+',消息:'+data.msg);switch(data.status){case 9003:messages('用户手机号不完整,请联系管理员.',opt);break;case 9005:messages('您操作频繁请稍后再试.',opt);break;case 9010:if(data.msg=='faceinfo not found'){messages('请先初始化该信息.',opt)}else if(data.msg=='voice not found'){messages('请先初始化该信息.',opt)}else{messages('请在手机上绑定该用户.',opt)}break;case 9017:goQrpage('手机端已拒绝您的请求,系统将自动跳到初始页面．',4000);break;case 9011:messages('验证码错误',opt);break;case 9001:messages('无效签名',opt);break;case 9009:goQrpage('签名已过期,系统将自动跳到初始页面．',4000);break;case 9019:messages('用户被禁用',opt);break;case 9020:messages(data.msg,opt);break;case 9999:goQrpage('会话马上过期,系统将自动跳到初始页面．',4000);break;case 9024:messages('由于您没有该应用的访问权限，芯盾统一身份认证无法通过您的认证请求，请与管理员联系.',{time:5000,shadeClose:true});break;default:messages(data.msg,opt);break}}function messages(msg,opt){if(msg){var opt=opt||{time:2500,shadeClose:true};layer.msg(msg,opt)}}function initParameter(){voiceCallTelNumber=$("#voiceCallTelNumber").val();if(voiceCallTelNumber!='null'&&voiceCallTelNumber.length>0){if(voiceCallTelNumber.length==11){voiceCallTelNumber=voiceCallTelNumber.substr(0,3)+'-'+voiceCallTelNumber.substr(3)}else if(voiceCallTelNumber.length==12){voiceCallTelNumber=voiceCallTelNumber.substr(0,4)+'-'+voiceCallTelNumber.substr(4)}}else{voiceCallTelNumber=''}}});